48	    if (!editingOutcomeId || !isConfigured) return;
49	    mutation.mutate({
50	      payload: {
51	        accountId: session.accountId,
52	        variableId: isTargetMarket ? targetMarket.variableId : m.variableId,
53	        target: { kind: "marginal", outcomeId: editingOutcomeId, probability: editValue },
54	        context: contextPayload,
55	        idempotencyKey: crypto.randomUUID(),
56	      },
