88	              {/* Probability display + inline bar */}
89	              <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
90	                <div style={{ flex: 1 }}>
91	                  <div style={{ height: 20, borderRadius: 4, background: "var(--color-border)", overflow: "hidden", position: "relative" }}>
92	                    <div style={{
93	                      height: "100%",
94	                      width: `${(isEditing ? editValue : p) * 100}%`,
95	                      borderRadius: 4,
96	                      background: isThisAssumed ? "var(--color-primary)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)",
97	                      opacity: isAssumed && !isThisAssumed ? 0.3 : 0.7,
98	                      transition: "width 0.2s ease",
99	                    }} />
100	                    <span style={{
101	                      position: "absolute",
102	                      top: 2,
103	                      left: 6,
104	                      fontSize: "0.7rem",
105	                      fontWeight: 600,
106	                      color: "var(--color-text)",
107	                    }}>
108	                      {o.name}: {formatProbability(isEditing ? editValue : p)}
109	                    </span>
110	                  </div>
111	                </div>
112	              </div>
113	
114	              {/* Action buttons */}
115	              <div style={{ display: "flex", gap: 4 }}>
116	                {!isTargetMarket && (
117	                  <button
118	                    onClick={() => handleAssume(o.id)}
119	                    style={{
120	                      ...actionBtnStyle,
121	                      background: isThisAssumed ? "var(--color-primary)" : "transparent",
122	                      color: isThisAssumed ? "#fff" : "var(--color-primary)",
123	                      border: `1px solid ${isThisAssumed ? "var(--color-primary)" : "var(--color-border)"}`,
124	                    }}
125	                  >
126	                    {isThisAssumed ? "✓ Assumed" : "Assume"}
127	                  </button>
128	                )}
129	                {isConfigured && !isEditing && (
130	                  <button
131	                    onClick={() => handleStartEdit(o.id, p)}
132	                    style={{ ...actionBtnStyle, border: "1px solid var(--color-border)" }}
133	                  >
134	                    Edit
135	                  </button>
136	                )}
137	              </div>
138	
139	              {/* Inline edit slider */}
140	              {isEditing && (
141	                <div style={{ marginTop: 4, display: "flex", gap: 4, alignItems: "center" }}>
142	                  <input
143	                    type="range"
144	                    min={0.01}
145	                    max={0.99}
146	                    step={0.01}
147	                    value={editValue}
148	                    onChange={(e) => setEditValue(Number(e.target.value))}
149	                    style={{ flex: 1 }}
150	                  />
151	                  <button onClick={handleSubmitEdit} style={submitBtnStyle} disabled={mutation.isPending}>
152	                    {mutation.isPending ? "…" : "Set"}
153	                  </button>
154	                  <button onClick={() => setEditingOutcomeId(null)} style={cancelBtnStyle}>✕</button>
155	                </div>
156	              )}
157	            </div>
158	          );
159	        })}
160	      </div>
161	
162	      {mutation.isSuccess && (
163	        <div style={{ fontSize: "0.7rem", color: "var(--color-success)", marginTop: 4 }}>
164	          Edit accepted: {mutation.data.order.orderId}
165	        </div>
