99	 * Optionally pre-populate assumptions via an `init` callback that fires
100	 * before the component under test mounts — we achieve this by rendering a
101	 * small bootstrapper that calls addAssumption inside an effect-free click.
102	 */
103	function renderPanel(
104	  { market = currentMarket, initialAssumptions = [] as Array<{ variableId: string; outcomeId: string; label: string }> } = {},
105	) {
106	  // We wrap in AssumptionProvider locally (decision d5).
107	  // To pre-seed assumptions, we render a helper button that adds them.
108	  function Wrapper() {
109	    return (
110	      <AssumptionProvider>
111	        <Seeder assumptions={initialAssumptions} />
112	        <AssumptionPanel market={market} />
113	      </AssumptionProvider>
114	    );
115	  }
